<script>
	export default {
		onLaunch() {
			// 检查是否显示过启动页
			const hasShownWelcome = uni.getStorageSync('hasShownWelcome')

			if (!hasShownWelcome) {
				// 首次启动跳转到欢迎页
				uni.reLaunch({
					url: '/pages/welcome/welcome'
				})
			} else {
				// 非首次启动直接进入主页
				uni.switchTab({
					url: '/pages/login/login'
				})
			}
		}
	}
</script>

<style>
	/*每个页面公共css */
</style>